UIDressStorePanItem = class("UIDressStorePanItem", IGUIWindow)

function UIDressStorePanItem:onLoad()
    self.siStatueBox = self:getChildWindow(0, GUIType.StaticImage)
    self.siImage = self:getChildWindow(1, GUIType.StaticImage)
    self.btnClickBox = self:getChildWindow(2, GUIType.Button)
    self.btnLine = self:getChildWindow(3, GUIType.Button)
    self.layNew = self:getChildWindow(4, GUIType.Layout)
    self.tvNewText = self:getChildWindow(0, GUIType.StaticText, self.layNew)
    self.layPrice = self:getChildWindow(5, GUIType.Layout)
    self.siPriceIcon = self:getChildWindow(0, GUIType.StaticImage, self.layPrice)
    self.stPriceText = self:getChildWindow(1, GUIType.StaticText, self.layPrice)
    self.layLock = self:getChildWindow(6, GUIType.Layout)
    self.layLockLevel = self:getChildWindow(0, GUIType.Button, self.layLock)

    self:registerEvent()
end

function UIDressStorePanItem:onDataChanged(data)
    local dress = UIDressStore:getDressData(data.Id)
    if not dress then
        return
    end
    self.Id = data.Id
    if dress.Status == 2 or dress.Status == 1 then
        --1 = NOT_GET   2 = NEW
        self.siStatueBox:SetImage("set:dress_shop.json image:not_get")
    elseif dress.Status == 0 then
        --0 = LOCK
        self.siStatueBox:SetImage("set:dress_shop.json image:lock")
    elseif dress.Status == 3 or dress.Status == 4 or dress.Status == 5 then
        self.siStatueBox:SetImage("set:dress_shop.json image:has_get")
    end
    if dress.Status ~= 0 then
        self.siImage:SetImage(data.Image)
    else
        self.siImage:SetImage(data.LockImage)
    end
    self.btnLine:SetVisible(dress.Status == 4 or dress.Status == 5) --4 = HAS_USE
    self.btnLine:SetText(Lang:getString("gui.btn.equipped"))
    self.layNew:SetVisible(dress.Status == 2)
    self.layPrice:SetVisible(dress.Status ~= 3 and dress.Status ~= 4 and dress.Status ~= 5)
    if dress.Status == 0 then
        self.siPriceIcon:SetArea({ 0, -58 }, { 0, 0 }, { 0, 35 }, { 0, 35 })
        self.siPriceIcon:SetImage("set:dress_shop.json image:chip")
    else
        self.siPriceIcon:SetArea({ 0, -58 }, { 0, 0 }, { 0, 50 }, { 0, 50 })
        self.siPriceIcon:SetImage(data.ChipImg)
    end
    self.layLock:SetVisible(dress.Status == 0)
    self.layLockLevel:SetText(data.UnlockLevel)
    self.stPriceText:SetText(string.format("%d/%d", dress.Chip, data.Price))
    if UIDressStore:isSelect(self.Id) and dress.Status ~= 0 then
        self.siStatueBox:SetImage("set:dress_shop.json image:select")
    end
    if Game:isChina() then
        self.tvNewText:SetText("新")
    else
        self.tvNewText:SetText("new")
    end
end

function UIDressStorePanItem:registerEvent()
    self.btnClickBox:registerEvent(GUIEvent.ButtonClick, function()
        self:onClock()
    end)
end

function UIDressStorePanItem:onClock()
    if not self.Id then
        return
    end
    local config = DressConfig:findStoreDressById(self.Id)
    if not config then
        return
    end
    local dress = UIDressStore:getDressData(self.Id)
    if not dress then
        return
    end
    if UIDressStore:isSelect(self.Id) and dress.Status ~= 0 then
        GUIStoreDressDetail:init(self.Id, dress.Chip)
    end
    if not UIDressStore:isSelect(self.Id) and dress.Status ~= 0 then
        self.siStatueBox:SetImage("set:dress_shop.json image:select")
    end
    if dress.Status == 0 then
        GUIDressStoreTip:setLockTip(config.UnlockLevel)
        GUIDressStoreTip:show()
    elseif dress.Status == 2 then
        UIDressStore:changeStatue(self.Id, 1)
        ShowUseDressEvent:invoke(self.Id)
        TableNewNumChangeEvent:invoke(config.TabType)
        self.layNew:SetVisible(false)
        GamePacketSender:sendBedWarFirstShowStoreDress(self.Id)
    else
        ShowUseDressEvent:invoke(self.Id)
    end
    UIDressStorePanItemChangeEvent:invoke(self.Id)
end
